PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?model ?modelLabel ?date WHERE {
  { ?model wdt:P279 wd:Q214276 }
  UNION
  { ?model wdt:P279 wd:Q111955126 }
  ?model wdt:P577 ?date .
  ?model rdfs:label ?modelLabel .
  FILTER(LANG(?modelLabel) = "en")
}
ORDER BY DESC(?date)
LIMIT 1

